#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>

using namespace std;

// Structure to hold the state in the priority queue: (Time, NegativeColor, Row, Col)
// We use negative color because std::priority_queue is a max-heap by default,
// and we want to prioritize smaller time (T) first, and then larger color (C) second.
// A smaller tuple lexicographically corresponds to a higher priority.
struct State {
    long long time;
    long long neg_color; // Storing -C
    int r, c;

    // Custom comparator for min-heap behavior based on (time, color)
    bool operator>(const State& other) const {
        if (time != other.time) {
            return time > other.time; // Minimize time
        }
        // If times are equal, prioritize larger color (smaller neg_color)
        return neg_color > other.neg_color;
    }
};


std::vector<std::vector<long long>> solve(long long n, long long m, std::vector<std::vector<long long>> sources) {
    // D[r][c] stores {Time, Color}. Initialize Time to infinity (a very large number), Color to 0.
    // Since N*M <= 10^5, Time won't exceed 10^5. We use -1 to represent infinity for simplicity in comparison if we stick to signed integers, but using LLONG_MAX is safer.

    // Since N and M are up to 10^5 individually, but N*M <= 10^5, we must use vectors of vectors.
    // We will use int for r and c indices since they are within grid bounds, even if N and M are long long.

    const long long INF_TIME = 2e14; // Sufficiently large number

    // Stores {Time, Color} for each cell
    vector<vector<pair<long long, long long>>> D(n, vector<pair<long long, long long>>(m, {INF_TIME, 0}));

    priority_queue<State, vector<State>, greater<State>> pq;

    // 1. Initialization from sources
    for (const auto& source : sources) {
        int r = (int)source[0];
        int c = (int)source[1];
        long long color = source[2];

        // Handle potential duplicate sources if constraints allowed, though problem states (r_i, c_i) are unique.
        if (D[r][c].first > 0) {
            D[r][c] = {0, color};
            pq.push({0, -color, r, c});
        } else {
             D[r][c] = {0, color};
             pq.push({0, -color, r, c});
        }
    }

    int dr[] = {-1, 1, 0, 0};
    int dc[] = {0, 0, -1, 1};

    // 2. Dijkstra's Algorithm
    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        long long T = current.time;
        long long C = -current.neg_color;
        int r = current.r;
        int c = current.c;

        // Check for outdated entry
        // The state stored in D[r][c] must match the state popped from PQ to be relevant.
        if (T > D[r][c].first || (T == D[r][c].first && C < D[r][c].second)) {
            continue;
        }

        // Explore neighbors
        for (int i = 0; i < 4; ++i) {
            int nr = r + dr[i];
            int nc = c + dc[i];

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                long long T_new = T + 1;
                long long C_new = C;

                long long T_old = D[nr][nc].first;
                long long C_old = D[nr][nc].second;

                bool improvement = false;

                // Check if (T_new, C_new) is strictly better than (T_old, C_old)
                if (T_new < T_old) {
                    // Faster arrival time always wins
                    improvement = true;
                } else if (T_new == T_old) {
                    // Tie in time: higher color wins
                    if (C_new > C_old) {
                        improvement = true;
                    }
                }

                if (improvement) {
                    D[nr][nc] = {T_new, C_new};
                    pq.push({T_new, -C_new, nr, nc});
                }
            }
        }
    }

    // 3. Format output
    vector<vector<long long>> result(n, vector<long long>(m));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            // The final color is stored in D[i][j].second
            // Since all cells must eventually be colored if N*M > 0, the time should not be INF_TIME unless the grid is empty, 
            // but since N*M >= 1, this is safe.
            result[i][j] = D[i][j].second;
        }
    }

    return result;
}

